2009: 	switch res := resp.Response.(type) {
2010: 	case *proto.MFAAuthenticateResponse_TOTP:
2011: 		return a.checkOTP(user, res.TOTP.Code)
2012: 	case *proto.MFAAuthenticateResponse_U2F:
