{"content":"839: func (a *Server) U2FSignRequest(user string, password []byte) (*U2FAuthenticateChallenge, error) {
840: 	ctx := context.TODO()
841: 	cap, err := a.GetAuthPreference()
842: 	if err != nil {
843: 		return nil, trace.Wrap(err)
844: 	}
845: 
846: 	u2fConfig, err := cap.GetU2F()
847: 	if err != nil {
848: 		return nil, trace.Wrap(err)
849: 	}
850: 
851: 	err = a.WithUserLock(user, func() error {
852: 		return a.CheckPasswordWOToken(user, password)
853: 	})
854: 	if err != nil {
855: 		return nil, trace.Wrap(err)
856: 	}
857: 
858: 	devs, err := a.GetMFADevices(ctx, user)
859: 	if err != nil {
860: 		return nil, trace.Wrap(err)
861: 	}
862: 	res := new(U2FAuthenticateChallenge)
863: 	for _, dev := range devs {
864: 		if dev.GetU2F() == nil {
865: 			continue
866: 		}
867: 		ch, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
868: 			Dev:        dev,
869: 			AppConfig:  *u2fConfig,
870: 			StorageKey: user,
871: 			Storage:    a.Identity,
872: 		})
873: 		if err != nil {
874: 			return nil, trace.Wrap(err)
875: 		}
876: 		res.Challenges = append(res.Challenges, *ch)
877: 		if res.AuthenticateChallenge == nil {
878: 			res.AuthenticateChallenge = ch
879: 		}
880: 	}
881: 	if len(res.Challenges) == 0 {
882: 		return nil, trace.NotFound("no U2F devices found for user %q", user)
883: 	}
884: 	return res, nil
885: }
