1214: func (g *GRPCServer) AddMFADevice(stream proto.AuthService_AddMFADeviceServer) error {
1215: 	actx, err := g.authenticate(stream.Context())
1216: 	if err != nil {
1217: 		return trail.ToGRPC(err)
