1219: 
1220: 	// The RPC is streaming both ways and the message sequence is:
1221: 	// (-> means client-to-server, <- means server-to-client)
1222: 	//
1223: 	// 1. -> Init
1224: 	// 2. <- ExistingMFAChallenge
1225: 	// 3. -> ExistingMFAResponse
1226: 	// 4. <- NewMFARegisterChallenge
1227: 	// 5. -> NewMFARegisterResponse
1228: 	// 6. <- Ack
1229: 
1230: 	// 1. receive client Init
1231: 	initReq, err := addMFADeviceInit(actx, stream)
1232: 	if err != nil {
1233: 		return trail.ToGRPC(err)
1234: 	}
1235: 
1236: 	// 2. send ExistingMFAChallenge
1237: 	// 3. receive and validate ExistingMFAResponse
1238: 	if err := addMFADeviceAuthChallenge(actx, stream); err != nil {
