// testMultiDeviceU2FAuthenticationFlow tests the complete authentication flow with multiple devices.
func testMultiDeviceU2FAuthenticationFlow(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Setup auth server
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create a test user with a password
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user", []string{"role"})
	require.NoError(t, err)

	password := "test-password-123"
	err = as.AuthServer.UpsertPassword(user.GetName(), []byte(password))
	require.NoError(t, err)

	// Register first U2F device
	device1, err := mocku2f.Create()
	require.NoError(t, err)
	_, err = registerU2FDevice(ctx, as.AuthServer, user.GetName(), "u2f-dev-1", device1)
	require.NoError(t, err)

	// Register second U2F device
	device2, err := mocku2f.Create()
	require.NoError(t, err)
	_, err = registerU2FDevice(ctx, as.AuthServer, user.GetName(), "u2f-dev-2", device2)
	require.NoError(t, err)

	// Request U2F sign challenge (used for login)
	challenge, err := as.AuthServer.U2FSignRequest(user.GetName(), []byte(password))
	require.NoError(t, err)

	// REGRESSION TEST: U2FSignRequest should return challenges for all devices
	// This is used by the web and CLI clients to get the challenge for authentication
	require.NotNil(t, challenge, "Challenge should not be nil")
	require.Len(t, challenge.Challenges, 2, "Expected 2 challenges in Challenges field (one for each device)")

	// Verify challenges are from both registered devices
	device1KeyHandle := device1.KeyHandle
	device2KeyHandle := device2.KeyHandle

	found1 := false
	found2 := false

	for _, chal := range challenge.Challenges {
		if chal.KeyHandle == device1KeyHandle {
			found1 = true
		}
		if chal.KeyHandle == device2KeyHandle {
			found2 = true
		}
	}

	require.True(t, found1, "Challenge for device 1 (keyHandle=%s) was not found", device1KeyHandle)
	require.True(t, found2, "Challenge for device 2 (keyHandle=%s) was not found", device2KeyHandle)

	// Test that both devices can authenticate
	for deviceIdx, device := range []*mocku2f.Key{device1, device2} {
		deviceNum := deviceIdx + 1
		t.Logf("Testing authentication with device %d", deviceNum)

		// Get the challenge for this device
		var deviceChallenge *u2f.AuthenticateChallenge
		for _, chal := range challenge.Challenges {
			if chal.KeyHandle == device.KeyHandle {
				deviceChallenge = &chal
				break
			}
		}
		require.NotNil(t, deviceChallenge, "Challenge for device %d not found", deviceNum)

		// Create a sign response using the device
		resp, err := device.SignResponse(deviceChallenge)
		require.NoError(t, err, "Failed to sign challenge with device %d", deviceNum)

		// Verify the signature
		err = as.AuthServer.CheckU2FSignResponse(ctx, user.GetName(), resp)
		require.NoError(t, err, "Failed to verify signature from device %d", deviceNum)
	}

	// Test device deletion
	devices, err := as.AuthServer.GetMFADevices(ctx, user.GetName())
	require.NoError(t, err)
	require.Len(t, devices, 2)

	// Delete the first device
	err = as.AuthServer.DeleteMFADevice(ctx, user.GetName(), devices[0].Id)
	require.NoError(t, err)

	// Verify only one device remains
	devices, err = as.AuthServer.GetMFADevices(ctx, user.GetName())
	require.NoError(t, err)
	require.Len(t, devices, 1, "After deleting one device, only 1 should remain")

	// Get challenge again - should only have one challenge now
	challenge, err = as.AuthServer.U2FSignRequest(user.GetName(), []byte(password))
	require.NoError(t, err)
	require.Len(t, challenge.Challenges, 1, "After deleting one device, should only have 1 challenge")
}

// registerU2FDevice is a helper function to register a U2F device for a user.
func registerU2FDevice(ctx context.Context, authServer *auth.Server, username, deviceName string, device *mocku2f.Key) (*types.MFADevice, error) {
	// Get auth preference to get U2F config
	authPref, err := authServer.GetAuthPreference()
	if err != nil {
		return nil, err
	}

	u2fConfig, err := authPref.GetU2F()
	if err != nil {
		return nil, err
	}

	// Create registration challenge
	regChallenge, err := u2f.RegisterInit(u2f.RegisterInitParams{
		StorageKey: username,
		AppConfig:  *u2fConfig,
		Storage:    authServer.Identity,
	})
	if err != nil {
		return nil, err
	}

	// Get device response to challenge
	deviceResp, err := device.RegisterResponse(regChallenge)
	if err != nil {
		return nil, err
	}

	// Register the device
	mfaDevice, err := u2f.RegisterVerify(u2f.RegisterVerifyParams{
		Resp:      deviceResp,
		Challenge: regChallenge,
		Clock:     authServer.GetClock(),
	})
	if err != nil {
		return nil, err
	}

	mfaDevice.Metadata.Name = deviceName

	// Store the device
	err = authServer.UpsertMFADevice(ctx, username, mfaDevice)
	if err != nil {
		return nil, err
	}

	return mfaDevice, nil
}

